public enum Color
{
    Red,
    Green,
    Blue
}

public static class ColorExtensions
{
    public static string ToDescription(this Color color)
    {
        switch (color)
        {
            case Color.Red:
                return "Red color";
            case Color.Green:
                return "Green color";
            case Color.Blue:
                return "Blue color";
            default:
                throw new ArgumentException("Invalid color", nameof(color));
        }
    }

    public static string ToHexCode(this Color color)
    {
        switch (color)
        {
            case Color.Red:
                return "#FF0000";
            case Color.Green:
                return "#00FF00";
            case Color.Blue:
                return "#0000FF";
            default:
                throw new ArgumentException("Invalid color", nameof(color));
        }
    }
}
```

